class Solution {
    public int minDays(int n) {
        if (n == 1) return 1;
        if (n == 2) return 2;
        if (n == 3) return 2;
        int days = 0;
        while (n > 0) {
            if (n % 3 == 0) {
                days += (n / 3);
                n = 0;
            } else if (n % 2 == 0) {
                days += 1;
                n /= 2;
            } else {
                days += 1;
                n -= 1;
            }
        }
        return days;
    }
}
```
